use std::collections::HashMap;

struct RequestData {
    data: HashMap<String, String>,
}

impl RequestData {
    fn new(data: HashMap<String, String>) -> Self {
        RequestData { data }
    }

    fn validate_and_process(&self) -> Result<(), String> {
        if !self.data.contains_key("user_id") || self.data["user_id"].is_empty() {
            return Err("Missing required user identifier in the request body.".to_string());
        }

        let user_id = &self.data["user_id"];
        if !user_id.starts_with("cli_") {
            return Err("User ID format is invalid; must start with 'cli_' prefix.".to_string());
        }

        println!("Successfully validated request for user: {}", user_id);
        Ok(())
    }
}

fn main() {
    let mut data = HashMap::new();
    data.insert("user_id".to_string(), "cli_9876".to_string());
    data.insert("content".to_string(), "Template output body.".to_string());

    let request = RequestData::new(data);

    match request.validate_and_process() {
        Ok(()) => println!("Processing complete: Response ready."),
        Err(e) => eprintln!("Request failed validation: {}", e),
    }

    let mut bad_data = HashMap::new();
    bad_data.insert("user_id".to_string(), "local_123".to_string());
    let bad_request = RequestData::new(bad_data);
    match bad_request.validate_and_process() {
        Ok(()) => (),
        Err(e) => println!("Caught expected error: {}", e),
    }
}

