use std::fmt::{self, Display};
use std::error::Error;

trait ConfigFormat {
    fn format(&self) -> Result<String, Box<dyn Error>>;
}

struct AppConfig {
    server_name: String,
    port: u16,
    log_level: String,
}

impl Display for AppConfig {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Server: {}, Port: {}", self.server_name, self.port)
    }
}

impl ConfigFormat for AppConfig {
    fn format(&self) -> Result<String, Box<dyn Error>> {
        Ok(format!("Configuration formatted successfully for {}", self))
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let config = AppConfig {
        server_name: String::from("api.example.com"),
        port: 8080,
        log_level: String::from("info"),
    };
    let formatted = config.format()?;
    println!("{}", formatted);
    Ok(())
}

use std::iter::FromIterator;

struct GameAction {
    name: String,
    setup_logic: Vec<String>,
}

impl GameAction {
    fn new(name: &str) -> Self {
        GameAction {
            name: name.to_string(),
            setup_logic: Vec::new(),
        }
    }

    fn add_hook(&mut self, hook: &str) {
        self.setup_logic.push(hook.to_string());
    }

    fn execute_setup(&self) -> Result<(), String> {
        println!("Setting up action: {}", self.name);
        for i in 0..self.setup_logic.len() {
            print!("  [Hook {}]: Executing setup step...n", i + 1);
        }
        Ok(())
    }
}

fn main() {
    let mut action = GameAction::new("player_jump");
    action.add_hook(&format!("Initialize particle effects for {}", "player"));
    action.add_hook(&format!("Register collision handler for {} jump", "player"));

    match action.execute_setup() {
        Ok(_) => println!("Setup complete successfully."),
        Err(e) => eprintln!("Fatal setup error: {}", e),
    }
}

